from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a city (or related entities) into a single fluent sentence."""
    if not triples:
        return ""

    # Group triples by subject for better organization
    subject_triples = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Identify the main subject (prefer city/county entities)
    main_subject = None
    for subj in subject_triples.keys():
        if any(keyword in subj for keyword in ["City", "County", "Texas", "California", "Ohio"]):
            main_subject = subj
            break
    if not main_subject:
        main_subject = triples[0].subject

    # Build main sentence parts for the main subject
    main_parts = []
    related_parts = []

    # Process triples for main subject
    if main_subject in subject_triples:
        for triple in subject_triples[main_subject]:
            phrase = get_phrase(triple.predicate, triple.object, main_subject)
            main_parts.append(phrase)

    # Process triples for other subjects (for related information)
    for subj, triple_list in subject_triples.items():
        if subj != main_subject:
            for triple in triple_list:
                phrase = get_phrase(triple.predicate, triple.object, subj)
                related_parts.append((subj, phrase))

    # Build the sentence efficiently
    if not main_parts:
        return main_subject

    sentence = f"{main_subject} {main_parts[0]}"
    for i, part in enumerate(main_parts[1:], 1):
        sentence += f", {part}"

    # Add related clauses in a coherent way
    for subj, clause in related_parts:
        if " is " in clause or " has " in clause:
            parts = clause.split(" ", 1)
            if len(parts) == 2:
                sentence += f", which {parts[1]}"
            else:
                sentence += f", and {clause}"
        else:
            sentence += f", and {clause}"

    sentence += "."

    # Ensure proper capitalization
    if sentence and sentence[0].islower():
        sentence = sentence[0].upper() + sentence[1:]

    return sentence

def get_phrase(predicate: str, obj: str, subj: str) -> str:
    """Generate a phrase from a predicate and object."""
    if predicate == "areaOfWater":
        return f"has a water area of {obj}"
    elif predicate == "areaTotal":
        return f"has a total area of {obj}"
    elif predicate == "country":
        return f"is in {obj}"
    elif predicate == "elevationAboveTheSeaLevel":
        return f"sits at an elevation of {obj} above sea level"
    elif predicate == "isPartOf":
        return f"is part of {obj}"
    elif predicate == "populationDensity":
        return f"has a population density of {obj}"
    elif predicate == "areaCode":
        return f"uses area code(s) {obj}"
    elif predicate == "leaderTitle":
        return f"has a {obj.lower()}"
    elif predicate == "areaOfLand":
        return f"has a land area of {obj}"
    elif predicate == "leader":
        return f"'s leader is {obj}"
    elif predicate == "utcOffset":
        return f"has a UTC offset of {obj}"
    elif predicate == "populationTotal":
        return f"has a total population of {obj}"
    elif predicate == "postalCode":
        return f"uses postal code(s) {obj}"
    elif predicate == "largestCity":
        return f"'s largest city is {obj}"
    elif predicate == "language":
        return f"uses the {obj}"
    elif predicate == "location":
        return f"is located at {obj}"
    elif predicate == "chairperson":
        return f"'s chairperson is {obj}"
    elif predicate == "headquarter":
        return f"'s headquarters is at {obj}"
    elif predicate == "countySeat":
        return f"'s county seat is {obj}"
    elif predicate == "capital":
        return f"'s capital is {obj}"
    elif predicate == "demonym":
        return f"people from {subj} are called {obj}"
    elif predicate == "ethnicGroup":
        return f"includes {obj} as an ethnic group"
    elif predicate == "state":
        return f"is in {obj}"
    elif predicate == "populationMetro":
        return f"has a metropolitan population of {obj}"
    elif predicate == "type":
        return f"is a {obj}"
    elif predicate == "governmentType":
        return f"has a {obj}"
    elif predicate == "timeZone":
        return f"is in the {obj} time zone"
    else:
        return f"{subj} {predicate} {obj}"

